+        assert_eq!(decision.lane, HostcallDispatchLane::Fast);
+        assert_eq!(
+            decision.fallback_reason,
+            Some(IoUringFallbackReason::IoUringDisabled)
+        );
+    }
+
+    #[test]
+    fn unavailable_ring_falls_back_to_fast_lane() {
+        let mut config = enabled_config();
